const all = $input.all().map(i=>i.json);
// Group by company+plan, compare latest vs prev
const byKey = {};
for (const r of all) {
  const key = `${r.company}::${r.plan_name}`;
  if (!byKey[key]) byKey[key] = [];
  byKey[key].push(r);
}
const changes = [];
const current = [];
for (const [key, records] of Object.entries(byKey)) {
  const sorted = records.sort((a,b)=>a.scraped_at<b.scraped_at?-1:1);
  const latest = sorted[sorted.length-1];
  const prev = sorted[sorted.length-2];
  current.push(latest);
  if (prev && (prev.price !== latest.price || prev.billing_cycle !== latest.billing_cycle)) {
    changes.push({ company: latest.company, plan: latest.plan_name, old_price: prev.price, new_price: latest.price, old_cycle: prev.billing_cycle, new_cycle: latest.billing_cycle, detected_at: latest.scraped_at });
  }
}
return [{ json: { date: new Date().toISOString().slice(0,10), changes_count: changes.length, changes, current_pricing: current } }];

