const data = $('Detect Changes').first().json;
let analysis;
try { analysis = JSON.parse(($input.first().json.message?.content||'{}').replace(/```json|```/g,'').trim()); } catch { analysis = {}; }
return [{ json: { date: data.date, changes_count: data.changes_count, changes: data.changes, generated_at: new Date().toISOString(), ...analysis } }];

